mapper.select:
SELECT COUNT(*)
  FROM EVS_OBJECT A
 WHERE A.RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}
   AND A.PERSON_ID  = #{adminID,   jdbcType=VARCHAR}

SELECT * FROM (
    SELECT INNER_Q.*, ROWNUM AS RN FROM (

        ORDER BY A.ORDERNO_DEPT, A.ORDERNO, A.DATE_STARTED
    ) INNER_Q
    WHERE ROWNUM <= #{start, jdbcType=INTEGER} + #{length, jdbcType=INTEGER}
) WHERE RN > #{start, jdbcType=INTEGER}

